from collections import defaultdict
d=defaultdict(list)
for line in open('gaa.trn',encoding='utf-8'):
    line=line.rstrip('\n')
    if not line: continue
    lemma,form,feats=line.split('\t')
    d[feats].append((lemma,form))
def analyze(f):
    print('===',f,'===')
    pfx=sfx=ident=0
    exc=[]
    for lemma,form in d[f]:
        if form==lemma: ident+=1
        elif form.endswith(lemma): pass # prefix
        elif form.startswith(lemma): pass
        else: exc.append((lemma,form))
    # compute prefix/suffix
    for lemma,form in d[f]:
        if form==lemma:
            cat='ID'
        elif form.endswith(lemma):
            cat='PFX:'+form[:len(form)-len(lemma)]
        elif form.startswith(lemma):
            cat='SFX:'+form[len(lemma):]
        else:
            cat='OTHER:'+lemma+'/'+form
        exc.append(cat)
    from collections import Counter
    c=Counter(exc)
    for k,v in c.most_common():
        print(f'  {v:3d}  {k}')
for f in ['V;NFIN','V;PRS','V;HAB;PRS','V;HAB;PST','V;HAB;FUT','V;NEG;PRS','V;HAB;NEG;PRS','V;HAB;NEG;PST','V;HAB;NEG;FUT']:
    analyze(f)
